2. 编辑 src/lib/server/terminal-manager.ts，在 constructor 中现有的 this.eventBus.subscribe(TerminalEvents.INPUT, ...) 块之后，添加两个订阅: 
- this.eventBus.subscribe(TerminalEvents.CREATE, (payload) => { const { terminalId, options } = payload as { terminalId: string; options?: Record<string, unknown> }; this.createTerminal(terminalId, options as CreateTerminalOptions); });
- this.eventBus.subscribe(TerminalEvents.DESTROY, (payload) => { const { terminalId } = payload as { terminalId: string }; this.destroyTerminal(terminalId); });

reference.examples:
TerminalManager 构造器中现有的 INPUT 订阅:
this.eventBus.subscribe(TerminalEvents.INPUT, (payload) => {
  const { terminalId, data } = payload as { terminalId: string; data: string };
  const active = this.sessions.get(terminalId);
  if (active) { active.pty.write(data); }
});
